export const ICON_NAMES = Object.keys(SOURCES);

export function Icon({ name, size = 64, title, style, className }) {
  const px = Number(size) || 64; // coerce — <x-import> passes attributes as strings
  const svg = SOURCES[name];
  if (!svg) {
    if (typeof console !== "undefined") {
      console.warn('Icon: unknown name "' + name + '". Expected one of ' + ICON_NAMES.join(", "));
    }
    return null;
  }
  return (
    <span
      role="img"
      aria-label={title || name}
      className={className}
      style={{
        display: "inline-flex",
        width: px,
        height: px,
        lineHeight: 0,
        flex: "0 0 auto",
        color: "var(--text-primary)",
        ...style,
      }}
      dangerouslySetInnerHTML={{ __html: svg }}
    />
  );
}
